// Tutorial controller — generated by add_tutorial.py
// No outlet connections required; manipulates patcher objects directly.
//
// Inlet 0: int (step index from umenu), bang (init), "prev" / "next"

inlets  = 1;
outlets = 0;

var STEPS         = [
  {
    "name": "Overview",
    "description": "This patch has 23 processing objects across 9 stages. Use the menu or prev/next to step through each stage."
  },
  {
    "name": "loadmess + unpack",
    "description": "loadmess \u2014 Sends a stored message when the patch loads (initializes defaults). unpack \u2014 Unpacks a list into individual outlet values."
  },
  {
    "name": "toggle +3",
    "description": "toggle \u2014 Sends 1 (on) or 0 (off) when clicked \u2014 starts/stops loops. metro \u2014 Generates repeated bangs at a set interval (ms). counter \u2014 Counts bangs up/down between min and max. +."
  },
  {
    "name": "loadmess +3",
    "description": "loadmess: rests (0=rest, 1=note). multislider. gate: velocity. makenote \u2014 Generates a MIDI note-on followed by a note-off."
  },
  {
    "name": "number",
    "description": "number \u2014 Displays and edits an integer number."
  },
  {
    "name": "number",
    "description": "number \u2014 Displays and edits an integer number. number \u2014 Displays and edits an integer number."
  },
  {
    "name": "t +2",
    "description": "t \u2014 Fires a series of typed outputs in right-to-left order. prepend: pitch (MIDI 36-84). prepend \u2014 Prepends a fixed message selector before incoming data. multislider."
  },
  {
    "name": "number",
    "description": "number \u2014 Displays and edits an integer number."
  },
  {
    "name": "pack +3",
    "description": "pack \u2014 Packs individual values into a single output list. midiformat \u2014 Assembles raw MIDI bytes from component values. abl.device.drift~. live.gain~ \u2014 A stereo volume fader (Max for Live)."
  },
  {
    "name": "ezdac~",
    "description": "ezdac~ \u2014 A stereo audio output with built-in gain slider."
  }
];
var ANNOTATION_IDS = ["tut-ann-0", "tut-ann-1", "tut-ann-2", "tut-ann-3", "tut-ann-4", "tut-ann-5", "tut-ann-6", "tut-ann-7", "tut-ann-8", "tut-ann-9"];
var PANEL_IDS      = ["tut-panel-0", "tut-panel-1", "tut-panel-2", "tut-panel-3", "tut-panel-4", "tut-panel-5", "tut-panel-6", "tut-panel-7", "tut-panel-8", "tut-panel-9"];

var currentStep = -1;

// ---- inlet handlers ----

function bang() {
    gotoStep(0);
}

function msg_int(step) {
    gotoStep(step);
}

function prev() {
    gotoStep(Math.max(0, currentStep - 1));
}

function next() {
    gotoStep(Math.min(STEPS.length - 1, currentStep + 1));
}

// ---- core ----

function gotoStep(step) {
    if (step < 0 || step >= STEPS.length) return;

    var p = this.patcher;

    // Hide all panels and annotation comments
    for (var i = 0; i < PANEL_IDS.length; i++) {
        var obj = p.getnamed(PANEL_IDS[i]);
        if (obj) obj.hidden = 1;
    }
    for (var i = 0; i < ANNOTATION_IDS.length; i++) {
        var obj = p.getnamed(ANNOTATION_IDS[i]);
        if (obj) obj.hidden = 1;
    }

    currentStep = step;

    // Show this step's panel and annotation
    var panel = p.getnamed(PANEL_IDS[step]);
    if (panel) panel.hidden = 0;

    var ann = p.getnamed(ANNOTATION_IDS[step]);
    if (ann) ann.hidden = 0;

    post("Tutorial step " + step + ": " + STEPS[step].name + "\n");
}
